module top_module(
    input clk,
    input reset,    
    input j,
    input k,
    output out);parameter OFF=0, ON=1; 
    reg state, next_state;

    always @(*) begin

        case(state)
            OFF: next_state = (j)? ON:OFF;
            ON: next_state = (k)? OFF:ON;
        endcase
    end

    always @(posedge clk) begin

        if (reset)
            state <= OFF;
        else
            state <= next_state;
    end


      wire _n01 = state[0] ^ ON[0];
  wire _n02 = state[1] ^ ON[1];
  wire _n03 = state[2] ^ ON[2];
  wire _n04 = state[3] ^ ON[3];
  assign out = ~_n01 & ~_n02 & ~_n03 & ~_n04;

endmodule
